const items = $input.all();

if (!items || items.length === 0) {
  console.log('Nenhum card recebido do Supabase');
  return [];
}

console.log(`Cards recebidos: ${items.length}`);

// SEMPRE trabalhar em UTC puro para evitar problemas de fuso
const agoraUTC = Date.now(); // ms desde epoch, sempre UTC

const resultado = [];

for (const item of items) {
  const card = item.json;
  if (!card.due_date || !card.titulo) continue;

  // Supabase retorna ISO string UTC (ex: "2026-06-05T14:30:00+00:00")
  const dueDateMs = new Date(card.due_date).getTime(); // ms UTC

  // Diferença em horas (positivo = futuro, negativo = passado)
  const diffHoras = (dueDateMs - agoraUTC) / (1000 * 60 * 60);

  console.log(`[${card.titulo.substring(0,35)}...] diff: ${diffHoras.toFixed(2)}h`);

  // Janelas de detecção — mais amplas para não perder por 1min
  // "HOJE":   leilão nas próximas 2h OU nas últimas 2h (cobrir se rodar atrasado)
  // "1 DIA":  entre 22h e 26h no futuro
  // "2 DIAS": entre 46h e 50h no futuro
  const isHoje  = diffHoras >= -2  && diffHoras <= 2;
  const is1dia  = diffHoras >= 22  && diffHoras <= 26;
  const is2dias = diffHoras >= 46  && diffHoras <= 50;

  if (!isHoje && !is1dia && !is2dias) continue;

  // Formatar para horário de Brasília (UTC-3)
  const dueDateObj = new Date(card.due_date);

  const dataFormatada = dueDateObj.toLocaleDateString('pt-BR', {
    timeZone: 'America/Sao_Paulo',
    weekday: 'long',
    day: '2-digit',
    month: 'long',
    year: 'numeric'
  });

  const horaFormatada = dueDateObj.toLocaleTimeString('pt-BR', {
    timeZone: 'America/Sao_Paulo',
    hour: '2-digit',
    minute: '2-digit'
  });

  const tituloResumido = card.titulo.length > 120
    ? card.titulo.substring(0, 120) + '...'
    : card.titulo;

  let tipoLembrete, emoji, urgencia;
  if (isHoje) {
    tipoLembrete = 'HOJE';
    emoji = '🔨';
    urgencia = 'LEILÃO HOJE! Acesse o link agora.';
  } else if (is1dia) {
    tipoLembrete = '1 DIA';
    emoji = '⚠️';
    urgencia = 'AMANHÃ! Confirme sua participação.';
  } else {
    tipoLembrete = '2 DIAS';
    emoji = '📅';
    urgencia = 'Prepare documentação e análise jurídica!';
  }

  const linhas = [
    `${emoji} *LEMBRETE DE LEILÃO — FALTAM ${tipoLembrete}*`,
    ``,
    `🏠 *Imóvel:*`,
    tituloResumido,
    ``,
    `📆 *Data:* ${dataFormatada}`,
    `🕐 *Horário:* ${horaFormatada}`,
    ``,
    `⚡ ${urgencia}`,
  ];

  if (card.link_leilao) {
    linhas.push(``);
    linhas.push(`🔗 *Link do leilão:*`);
    linhas.push(card.link_leilao);
  }

  linhas.push(``);
  linhas.push(`_FlowDesck · Ruah Systems_`);

  resultado.push({
    json: {
      id: card.id,
      titulo: card.titulo,
      due_date: card.due_date,
      link_leilao: card.link_leilao || '',
      mensagem: linhas.join('\n'),
      tipoLembrete,
      dataFormatada,
      horaFormatada,
      tituloResumido,
      diffHoras: parseFloat(diffHoras.toFixed(2))
    }
  });
}

console.log(`Lembretes gerados: ${resultado.length}`);
return resultado;
